package server

var dashboardHTML = []byte(`<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Stockyard Mailbag</title><style>:root{--bg:#1a1410;--surface:#241c15;--border:#3d2e1e;--rust:#c4622d;--cream:#f5e6c8;--muted:#7a6550;--text:#e8d5b0}*{box-sizing:border-box;margin:0;padding:0}body{background:var(--bg);color:var(--text);font-family:'JetBrains Mono',monospace,sans-serif}header{background:var(--surface);border-bottom:1px solid var(--border);padding:1rem 2rem;display:flex;align-items:center;gap:1rem}.logo{color:var(--rust);font-size:1.25rem;font-weight:700}.badge{background:var(--rust);color:var(--cream);font-size:0.65rem;padding:0.2rem 0.5rem;border-radius:3px;font-weight:600;text-transform:uppercase}main{max-width:1100px;margin:0 auto;padding:2rem}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;margin-bottom:2rem}.stat{background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:1.25rem;text-align:center}.stat-value{font-size:1.75rem;font-weight:700;color:var(--rust)}.stat-label{font-size:0.75rem;color:var(--muted);margin-top:0.25rem;text-transform:uppercase;letter-spacing:0.05em}.grid{display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin-bottom:2rem}.card{background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:1.5rem}.card h2{font-size:0.85rem;color:var(--muted);text-transform:uppercase;letter-spacing:0.08em;margin-bottom:1rem}.full{grid-column:1/-1}.form-row{display:flex;gap:0.5rem;margin-bottom:0.75rem;flex-wrap:wrap}select,input,textarea{background:var(--bg);border:1px solid var(--border);color:var(--text);padding:0.5rem 0.75rem;border-radius:4px;font-family:inherit;font-size:0.85rem;flex:1}textarea{resize:vertical;min-height:100px;flex:none;width:100%}.btn{background:var(--rust);color:var(--cream);border:none;padding:0.5rem 1rem;border-radius:4px;cursor:pointer;font-family:inherit;font-size:0.85rem;font-weight:600}.btn:hover{opacity:0.85}.btn-sm{padding:0.25rem 0.6rem;font-size:0.75rem}.btn-danger{background:#7a2020}table{width:100%;border-collapse:collapse;font-size:0.82rem}th{text-align:left;color:var(--muted);padding:0.5rem;border-bottom:1px solid var(--border);font-size:0.75rem;text-transform:uppercase}td{padding:0.5rem;border-bottom:1px solid var(--border)}.empty{color:var(--muted);font-size:0.85rem;padding:1rem 0;text-align:center}.badge-q{background:#1a2a3a;color:#5bc0de;border:1px solid #2d4a6a;border-radius:3px;padding:0.1rem 0.4rem;font-size:0.72rem}.badge-s{background:#1a3a1a;color:#5cb85c;border:1px solid #2d5a2d;border-radius:3px;padding:0.1rem 0.4rem;font-size:0.72rem}.badge-f{background:#3a1a1a;color:#d9534f;border:1px solid #5a2d2d;border-radius:3px;padding:0.1rem 0.4rem;font-size:0.72rem}.tabs{display:flex;gap:0.5rem;margin-bottom:1.5rem}.tab{background:var(--surface);border:1px solid var(--border);color:var(--muted);padding:0.5rem 1rem;border-radius:4px;cursor:pointer;font-size:0.85rem;font-family:inherit}.tab.active{background:var(--rust);color:var(--cream);border-color:var(--rust)}</style></head>
<body>
<header><span class="logo">&#x2B21; Stockyard</span><span style="color:var(--muted)">/</span><span style="color:var(--cream);font-weight:600">Mailbag</span><span class="badge">Email</span></header>
<main>
<div class="stats"><div class="stat"><div class="stat-value" id="s-q">0</div><div class="stat-label">Queued</div></div><div class="stat"><div class="stat-value" id="s-s">0</div><div class="stat-label">Sent</div></div><div class="stat"><div class="stat-value" id="s-f">0</div><div class="stat-label">Failed</div></div><div class="stat"><div class="stat-value" id="s-t">0</div><div class="stat-label">Templates</div></div></div>
<div class="tabs"><button class="tab active" onclick="showTab('compose')">Compose</button><button class="tab" onclick="showTab('templates')">Templates</button><button class="tab" onclick="showTab('messages')">Messages</button></div>
<div id="tab-compose">
<div class="card full"><h2>Compose &amp; Send</h2>
<div class="form-row"><input id="f-to" placeholder="To: recipient@example.com"><select id="f-tmpl" onchange="loadTemplate()"><option value="">-- Use Template (optional) --</option></select></div>
<div class="form-row"><input id="f-subj" placeholder="Subject"></div>
<textarea id="f-body" rows="8" placeholder="Email body. Use {{variable}} for template vars."></textarea>
<div style="margin-top:0.75rem"><button class="btn" onclick="send()">Queue Message</button></div>
</div></div>
<div id="tab-templates" style="display:none">
<div class="grid">
<div class="card"><h2>New Template</h2>
<div class="form-row"><input id="t-name" placeholder="Template name"></div>
<div class="form-row"><input id="t-subj" placeholder="Subject (use {{name}} for vars)"></div>
<textarea id="t-body" rows="6" placeholder="Body text. Use {{variable}} placeholders."></textarea>
<button class="btn btn-sm" style="margin-top:0.5rem" onclick="addTemplate()">Save Template</button></div>
<div class="card full"><h2>Saved Templates</h2><div id="tmpl-list"><div class="empty">No templates</div></div></div>
</div></div>
<div id="tab-messages" style="display:none">
<div class="card full"><h2>Messages <select id="msg-filter" onchange="loadMessages()" style="flex:0;width:auto;margin-left:0.5rem"><option value="">All</option><option>queued</option><option>sent</option><option>failed</option></select></h2>
<div id="msg-list"><div class="empty">No messages</div></div>
</div></div>
</main>
<script>
var tmpls=[];
function showTab(t){['compose','templates','messages'].forEach(function(id){var el=document.getElementById('tab-'+id);if(el)el.style.display=id===t?'block':'none'});document.querySelectorAll('.tab').forEach(function(b,i){b.classList.toggle('active',['compose','templates','messages'][i]===t)});if(t==='messages')loadMessages();if(t==='templates')loadTemplates()}
function load(){fetch('/api/stats').then(function(r){return r.json()}).then(function(d){document.getElementById('s-q').textContent=d.queued||0;document.getElementById('s-s').textContent=d.sent||0;document.getElementById('s-f').textContent=d.failed||0})}
function loadTemplateList(){fetch('/api/templates').then(function(r){return r.json()}).then(function(list){tmpls=list;document.getElementById('s-t').textContent=list.length;var sel=document.getElementById('f-tmpl');sel.innerHTML='<option value="">-- Use Template --</option>';list.forEach(function(t){sel.innerHTML+='<option value="'+t.id+'">'+t.name+'</option>'})})}
function loadTemplates(){fetch('/api/templates').then(function(r){return r.json()}).then(function(list){var el=document.getElementById('tmpl-list');el.innerHTML=list.length?'<table><thead><tr><th>Name</th><th>Subject</th><th></th></tr></thead><tbody>'+list.map(function(t){return'<tr><td style="color:var(--cream)">'+t.name+'</td><td>'+t.subject+'</td><td><button class="btn btn-sm btn-danger" onclick="delTemplate('+t.id+')">Delete</button></td></tr>'}).join('')+"</tbody></table>":'<div class="empty">No templates</div>'})}
function loadTemplate(){var id=document.getElementById('f-tmpl').value;if(!id)return;var t=tmpls.find(function(x){return x.id==id});if(t){document.getElementById('f-subj').value=t.subject;document.getElementById('f-body').value=t.body}}
function loadMessages(){var s=document.getElementById('msg-filter').value;fetch('/api/messages'+(s?'?status='+s:'')).then(function(r){return r.json()}).then(function(list){var el=document.getElementById('msg-list');var bc={queued:'badge-q',sent:'badge-s',failed:'badge-f'};el.innerHTML=list.length?'<table><thead><tr><th>To</th><th>Subject</th><th>Status</th><th>Time</th><th></th></tr></thead><tbody>'+list.map(function(m){return'<tr><td>'+m.to+'</td><td>'+m.subject+'</td><td><span class="'+(bc[m.status]||'')+'">'+m.status+'</span></td><td style="color:var(--muted);font-size:0.75rem">'+m.created_at+'</td><td>'+( m.status==='queued'?'<button class="btn btn-sm badge-s" onclick="markSent('+m.id+')">Mark Sent</button> ':'')+(m.status==='failed'?'<button class="btn btn-sm" onclick="markSent('+m.id+')">Retry</button> ':'')+ '<button class="btn btn-sm btn-danger" onclick="delMsg('+m.id+')">x</button></td></tr>'}).join('')+"</tbody></table>":'<div class="empty">No messages</div>';load()})}
function addTemplate(){var d={name:document.getElementById('t-name').value.trim(),subject:document.getElementById('t-subj').value.trim(),body:document.getElementById('t-body').value.trim()};if(!d.name||!d.subject||!d.body)return;fetch('/api/templates',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)}).then(function(){document.getElementById('t-name').value='';document.getElementById('t-subj').value='';document.getElementById('t-body').value='';loadTemplateList();loadTemplates()})}
function delTemplate(id){fetch('/api/templates/'+id,{method:'DELETE'}).then(function(){loadTemplateList();loadTemplates()})}
function send(){var d={to:document.getElementById('f-to').value.trim(),subject:document.getElementById('f-subj').value.trim(),body:document.getElementById('f-body').value.trim()};var tid=document.getElementById('f-tmpl').value;if(tid)d.template_id=parseInt(tid);if(!d.to||!d.subject||!d.body)return;fetch('/api/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)}).then(function(){document.getElementById('f-to').value='';document.getElementById('f-subj').value='';document.getElementById('f-body').value='';load()})}
function markSent(id){fetch('/api/messages/'+id,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'sent'})}).then(function(){loadMessages()})}
function delMsg(id){fetch('/api/messages/'+id,{method:'DELETE'}).then(function(){loadMessages();load()})}
load();loadTemplateList();
</script></body></html>`)
